class Solution:
    def partitionLabels(self, s):
        last = {c: i for i, c in enumerate(s)}
        res = []
        start = 0
        end = 0
        for i, c in enumerate(s):
            end = max(end, last[c])
            if i == end:
                res.append(i - start + 1)
                start = i + 1
        return res

